SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_fin_money_agent ON sc_fin_money_agent CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_fin_money_agent() RETURNS trigger AS $BODY$
BEGIN

    if coalesce(NEW.item_no::text, '') = '' or NEW.item_no = 0 then
        select max(item_no) into STRICT NEW.item_no
        from sc_fin_money_agent
        where AGENT_NO = NEW.AGENT_NO;
        NEW.item_no := coalesce(NEW.item_no,0) + 1;
    end if;

    if coalesce(NEW.cancel_status::text, '') = '' then NEW.cancel_status :='0';end if;
    if coalesce(NEW.return_status::text, '') = '' then NEW.return_status :='0';end if;

    if NEW.request_status ='1' and coalesce(NEW.paid_date::text, '') = ''  then
      NEW.paid_date :=  pka.to_date( to_char( statement_timestamp()  , 'dd/mm/yyyy' ) );
    end if;

    if NEW.request_status ='1' and NEW.return_status = '0'  then
      NEW.request_id :=  current_setting('app.login_id', true);
      NEW.request_date := statement_timestamp();
    end if;

--    if :new.request_status ='0'  then
--      :new.paid_date :=  null  ;
--      :new.request_id := null ;
--      :new.request_date := null ; 
--    end if; 
 if (  (OLD.AGENT_NO IS NOT NULL AND OLD.AGENT_NO::text <> '')  
        and  NEW.AGENT_NO <> OLD.AGENT_NO )  then 
    update sc_fin_money_agent_det
    set AGENT_NO = NEW.AGENT_NO
    where AGENT_NO = OLD.AGENT_NO
    and item_no = OLD.item_no;

 end if;

--Niorn 2023-05-05 TGE เพิ่มเก็บ entry_id , entry_date   
if coalesce(NEW.entry_id::text, '') = '' then NEW.entry_id :=  current_setting('app.login_id', true);end if;
if coalesce(NEW.entry_date::text, '') = '' then NEW.entry_date :=  statement_timestamp();end if;

RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_fin_money_agent() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_fin_money_agent
	BEFORE INSERT OR UPDATE ON sc_fin_money_agent FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_fin_money_agent();

